-- ============================================================
-- Migration 00039 : Club Directory — Schéma (idempotent) + Import Notion (882 clubs)
-- Généré le 2026-03-08
-- ============================================================

-- Enum via DO block (idempotent)
DO $enum$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'belgian_province') THEN
    CREATE TYPE belgian_province AS ENUM (
      'Anvers','Brabant flamand','Brabant wallon',
      'Flandre occidentale','Flandre orientale',
      'Hainaut','Liège','Limbourg','Luxembourg','Namur'
    );
  END IF;
END $enum$;

-- Table club_directory (idempotent)
CREATE TABLE IF NOT EXISTS club_directory (
  id                            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  tenant_id                     UUID        NOT NULL REFERENCES tenants(id),
  nom                           TEXT        NOT NULL,
  matricule                     TEXT,
  label                         TEXT,
  province                      belgian_province,
  adresse_rue                   TEXT,
  code_postal                   TEXT,
  ville                         TEXT,
  site_internet                 TEXT,
  correspondant                 TEXT,
  email_principal               TEXT,
  telephone_principal           TEXT,
  responsable_sportif           TEXT,
  email_responsable_sportif     TEXT,
  telephone_responsable_sportif TEXT,
  club_partenaire               BOOLEAN     NOT NULL DEFAULT false,
  actif                         BOOLEAN     NOT NULL DEFAULT true,
  notes_internes                TEXT,
  notion_page_id                TEXT        UNIQUE,
  notion_synced_at              TIMESTAMPTZ,
  deleted_at                    TIMESTAMPTZ,
  created_at                    TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at                    TIMESTAMPTZ NOT NULL DEFAULT now()
);

DO $rls$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename = 'club_directory' AND policyname = 'tenant_isolation') THEN
    ALTER TABLE club_directory ENABLE ROW LEVEL SECURITY;
    CREATE POLICY "tenant_isolation" ON club_directory FOR ALL USING (tenant_id = current_tenant_id());
  END IF;
END $rls$;

CREATE OR REPLACE FUNCTION set_club_directory_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN NEW.updated_at = now(); RETURN NEW; END; $$;

DROP TRIGGER IF EXISTS club_directory_updated_at ON club_directory;
CREATE TRIGGER club_directory_updated_at BEFORE UPDATE ON club_directory FOR EACH ROW EXECUTE FUNCTION set_club_directory_updated_at();

CREATE TABLE IF NOT EXISTS club_directory_child_links (
  club_id    UUID NOT NULL REFERENCES club_directory(id) ON DELETE CASCADE,
  child_id   UUID NOT NULL REFERENCES profiles(user_id) ON DELETE CASCADE,
  tenant_id  UUID NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (club_id, child_id)
);

CREATE TABLE IF NOT EXISTS club_directory_coach_links (
  club_id    UUID NOT NULL REFERENCES club_directory(id) ON DELETE CASCADE,
  coach_id   UUID NOT NULL REFERENCES profiles(user_id) ON DELETE CASCADE,
  tenant_id  UUID NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (club_id, coach_id)
);

CREATE INDEX IF NOT EXISTS idx_club_directory_tenant ON club_directory(tenant_id) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_club_directory_nom ON club_directory(tenant_id, nom) WHERE deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_club_directory_matricule ON club_directory(tenant_id, matricule) WHERE matricule IS NOT NULL AND deleted_at IS NULL;
CREATE INDEX IF NOT EXISTS idx_club_directory_notion ON club_directory(notion_page_id) WHERE notion_page_id IS NOT NULL;

-- ============================================================
-- Import des clubs depuis Notion
-- ============================================================
DO $$
DECLARE
  v_tenant_id UUID;
BEGIN
  SELECT id INTO v_tenant_id FROM tenants ORDER BY created_at LIMIT 1;
  IF v_tenant_id IS NULL THEN
    RAISE EXCEPTION 'Aucun tenant trouvé.';
  END IF;
  RAISE NOTICE 'Import vers tenant: %', v_tenant_id;


  RAISE NOTICE '882 clubs importés.';
END $$;
